        json.dump(state, f, ensure_ascii=False, indent=2)


def track_usage(skill_name):
    """Call this when a skill is loaded/used."""
    usage = _load_usage()
    entry = usage.get(skill_name, {})
    entry["use_count"] = entry.get("use_count", 0) + 1
    entry["last_used_at"] = time.time()
    usage[skill_name] = entry
    _save_usage(usage)


def maybe_run():
    """Run curator if enough time has passed. Returns report string or None."""
    state = _load_state()
    now = time.time()

    if state.get("last_run_at"):
        hours_since = (now - state["last_run_at"]) / 3600
        if hours_since < 24:  # Run at most once per day
            return None

    return run_curator()


def run_curator():
    """Run curation pass. Returns report string."""
    state = _load_state()
    skills = _load_skills()
    usage = _load_usage()
    now = time.time()

    if not skills:
        return "📚 No skills to curate."

    stale = []
    to_archive = []
    active = []
    pinned = []

    for skill in skills:
        name = skill.get("name", "")
        if skill.get("pinned"):
            pinned.append(name)
            continue
        if skill.get("archived"):
            continue

        last_used = usage.get(name, {}).get("last_used_at", 0)
        if last_used == 0:
            # Never used — use creation time
            last_used = skill.get("created_at", now)

        days_since = (now - last_used) / 86400

        if days_since >= ARCHIVE_AFTER_DAYS:
            to_archive.append((name, days_since))
        elif days_since >= STALE_AFTER_DAYS:
            stale.append((name, days_since))
        else:
            active.append(name)

    # Archive stale skills
    archived_names = []
    if to_archive:
        for skill in skills:
            if skill.get("name") in [n for n, _ in to_archive]:
                skill["archived"] = True
                skill["archived_at"] = now
                archived_names.append(skill["name"])
        _save_skills(skills)

    # Update state
    state["last_run_at"] = now
    state["run_count"] = state.get("run_count", 0) + 1
    state["archived"] = list(set(state.get("archived", []) + archived_names))
    _save_state(state)

    # Build report
    lines = [f"🧹 Skill Curator Run #{state['run_count']}"]
    lines.append(f"   Total skills: {len(skills)}")
    lines.append(f"   Active: {len(active)}")
    lines.append(f"   Stale (>{STALE_AFTER_DAYS}d unused): {len(stale)}")
    lines.append(f"   Archived (>{ARCHIVE_AFTER_DAYS}d unused): {len(archived_names)}")
    lines.append(f"   Pinned: {len(pinned)}")

    if stale:
        lines.append("\n   ⚠️ Stale skills:")
        for name, days in stale:
            lines.append(f"      - {name} ({days:.0f}d unused)")

    if archived_names:
        lines.append("\n   📦 Archived:")
        for name in archived_names:
            lines.append(f"      - {name}")

    return "\n".join(lines)


def usage_stats():
    """Return usage statistics for all skills."""
    skills = _load_skills()
    usage = _load_usage()

    if not skills:
        return "📚 No skills in library."

    lines = ["📊 Skill Usage Stats:"]
    for skill in skills:
        name = skill.get("name", "?")
        if skill.get("archived"):
            lines.append(f"  📦 {name} [ARCHIVED]")
            continue
        u = usage.get(name, {})
        count = u.get("use_count", 0)
        last = u.get("last_used_at")
        if last:
            days = (time.time() - last) / 86400
            last_str = f"{days:.0f}d ago"
        else:
            last_str = "never"
        pinned = " 📌" if skill.get("pinned") else ""
        lines.append(f"  {'✅' if count > 0 else '⚪'} {name}: {count}x used, last: {last_str}{pinned}")

    return "\n".join(lines)


def pin_skill(name):
    """Pin a skill so curator never archives it."""
    skills = _load_skills()
    for skill in skills:
        if skill.get("name", "").lower() == name.lower():
            skill["pinned"] = True
            _save_skills(skills)
            return f"📌 Pinned: {name}"
    return f"❌ Skill not found: {name}"


